mapper.select:
SELECT pp.* FROM project_progress pp


    INNER JOIN project_info pi ON pp.p_id = pi.id AND pi.sid = #{query.sid}



        AND pp.id = #{query.id}


        AND pp.p_id = #{query.pId}


        AND pp.status = #{query.status}


        AND pp.title LIKE CONCAT('%', #{query.title}, '%')


        AND pp.content LIKE CONCAT('%', #{query.content}, '%')


        AND pp.opinion LIKE CONCAT('%', #{query.opinion}, '%')




        AND pp.submit_time >= #{query.createTimeStart}


        AND pp.submit_time <= #{query.createTimeEnd}





        ORDER BY ${query.orderByClause}


        ORDER BY pp.id
        ASC
        DESC
